-- C Code Lab: questions seed (generated from seed_syllabus_questions + question_content)
-- Dialect: SQLite + PostgreSQL (no vendor-specific PRAGMA).
-- Clears attempts first (FK to questions), then questions, then inserts fresh rows.

BEGIN;
DELETE FROM attempts;
DELETE FROM questions;

