Problem style: Print Hello World. Read input from stdin and print exact output.', 'Phase 1 — Foundation', 'medium', 'No input.', 'Print exactly: Hello World', 'This program runs without waiting for typed input.', '', 'Hello World', '[{"input": "", "output": "Hello World"}, {"input": "", "output": "Hello World"}]', '[{"input": "", "output": "Hello World"}]', 15, 'There is nothing to calculate; emit the exact required text once.', '`printf()` only may be enough. Optional: wrap in `int main()` and return 0.', NULL);
INSERT INTO questions (title, description, module, difficulty, input_format, output_format, constraints, sample_input, expected_output, examples_json, test_cases_json, time_limit_minutes, algorithm_hint, functions_hint, efficient_solution) VALUES ('Phase 1 — Foundation Practice 2: Print name and city', 'Solve a phase 1 — foundation coding task focused on ''Structure of a C Program''.
